                      "code": "import json\nfrom dataclasses import dataclass, field\n\n@dataclass\nclass AdaptiveGate:\n    high_confidence_threshold: float = 0.85\n    low_confidence_threshold: float = 0.50\n    min_batch_size: int = 5\n    max_batch_size: int = 50\n    default_batch_size: int = 25\n    _recent_confidences: list = field(default_factory=list)\n    _window: int = 50\n\n    def record_confidence(self, conf):\n        self._recent_confidences.append(conf)\n        if len(self._recent_confidences) > self._window:\n            self._recent_confidences = self._recent_confidences[-self._window:]\n\n    @property\n    def rolling_mean(self):\n        if not self._recent_confidences:\n            return 0.5\n        return sum(self._recent_confidences) / len(self._recent_confidences)\n\n    @property\n    def recommended_batch_size(self):\n        mean = self.rolling_mean\n        if mean >= self.high_confidence_threshold:\n            return self.max_batch_size\n        elif mean <= self.low_confidence_threshold:\n            return self.min_batch_size\n        else:\n            ratio = (mean - self.low_confidence_threshold) / (self.high_confidence_threshold - self.low_confidence_threshold)\n            return int(self.min_batch_size + ratio * (self.max_batch_size - self.min_batch_size))\n\n    @property\n    def recommended_max_retries(self):\n        return 3 if self.rolling_mean < self.low_confidence_threshold else 1\n\n    def telemetry(self):\n        return {\n            \"rolling_mean_confidence\": round(self.rolling_mean, 4),\n            \"sample_size\": len(self._recent_confidences),\n            \"recommended_batch_size\": self.recommended_batch_size,\n            \"recommended_max_retries\": self.recommended_max_retries,\n        }\n\ngate = AdaptiveGate()\n\n# Batch 1: High-confidence records\nbatch1 = [\n    {\"id\": \"R-1\", \"name\": \"Pfizer\"},\n    {\"id\": \"R-2\", \"name\": \"Roche\"},\n    {\"id\": \"R-3\", \"name\": \"Novartis\"}\n]\nprompts = [f\"Classify: {json.dumps(r)}. Return JSON: {{id, confidence: 0-1}}\" for r in batch1]\nraw = llm_query_batched(prompts)\n\nfor r in raw:\n    obj = json.loads(r.strip())\n    gate.record_confidence(obj[\"confidence\"])\n\nprint(f\"After batch 1: {gate.telemetry()}\")\nbatch1_size = gate.recommended_batch_size"
