                      "code": "import json\nfrom enum import Enum\nfrom pydantic import BaseModel, Field, model_validator\nfrom typing import Optional\n\nclass Disposition(str, Enum):\n    EXACT_MATCH = \"exact_match\"\n    FUZZY_MATCH = \"fuzzy_match\"\n    NEEDS_CONTEXT = \"needs_context\"\n    ANOMALY = \"anomaly\"\n    SKIP = \"skip\"\n\nclass TriageDecision(BaseModel):\n    record_id: str\n    disposition: Disposition\n    confidence: float = Field(ge=0.0, le=1.0)\n    rationale: str = Field(max_length=300)\n    matched_entity_id: Optional[str] = None\n    missing_fields: list[str] = Field(default_factory=list)\n\n    @model_validator(mode=\"after\")\n    def enforce_match_has_entity(self) -> \"TriageDecision\":\n        if self.disposition in (Disposition.EXACT_MATCH, Disposition.FUZZY_MATCH):\n            if not self.matched_entity_id:\n                raise ValueError(f\"disposition={self.disposition.value} requires matched_entity_id\")\n        return self\n\nrecords = [\n    {\"id\": \"REC-001\", \"name\": \"Medtronic Inc\", \"city\": \"Minneapolis\"},\n    {\"id\": \"REC-002\", \"name\": \"Jhonson & Johnson\", \"city\": \"New Brunswick\"},\n    {\"id\": \"REC-003\", \"name\": \"Unknown Pharma XYZ\", \"city\": \"\"}\n]\n\nknown_entities = [\n    {\"id\": \"ENT-100\", \"canonical_name\": \"Medtronic PLC\"},\n    {\"id\": \"ENT-200\", \"canonical_name\": \"Johnson & Johnson\"}\n]\n\nsymbol_table = \"\\n\".join(f\"  {e['id']}: {e['canonical_name']}\" for e in known_entities)\nschema_json = json.dumps(TriageDecision.model_json_schema(), indent=2)\n\nprompts = []\nfor r in records:\n    prompts.append(\n        f\"Classify this record. Known entities:\\n{symbol_table}\\n\"\n        f\"Schema:\\n{schema_json}\\nRecord:\\n{json.dumps(r)}\\nReturn JSON only.\"\n    )\n\nraw_responses = llm_query_batched(prompts)\n\ndecisions = []\nerrors = []\nfor r, raw in zip(records, raw_responses):\n    try:\n        cleaned = raw.strip()\n        if cleaned.startswith(\"```\"):\n            cleaned = cleaned.split(\"\\n\", 1)[-1].rsplit(\"```\", 1)[0].strip()\n        obj = json.loads(cleaned)\n        decision = TriageDecision.model_validate(obj)\n        if decision.matched_entity_id and decision.matched_entity_id not in symbol_table:\n            raise ValueError(f\"Hallucinated entity ID: {decision.matched_entity_id}\")\n        decisions.append(decision)\n    except Exception as exc:\n        errors.append({\"record_id\": r[\"id\"], \"error\": str(exc)})\n\nprint(f\"Decisions: {len(decisions)}, Errors: {len(errors)}\")\nfor d in decisions:\n    print(f\"  {d.record_id} -> {d.disposition.value} (conf={d.confidence})\")"
