              "parts": [
                {
                  "functionCall": {
                    "name": "execute_code",
                    "args": {
                      "code": "import json\nfrom dataclasses import dataclass\nfrom typing import Any\n\n@dataclass\nclass SlidingWindow:\n    window_size: int = 4\n    prefix_ratio: float = 0.5\n\n    @property\n    def stride(self):\n        return int(self.window_size * (1 - self.prefix_ratio))\n\n    def chunks(self, data):\n        result = []\n        overlap = self.window_size - self.stride\n        for start in range(0, len(data), self.stride):\n            end = min(start + self.window_size, len(data))\n            full_window = data[start:end]\n            if start == 0:\n                prefix, actionable = [], full_window\n            else:\n                prefix = full_window[:overlap]\n                actionable = full_window[overlap:]\n            if actionable:\n                result.append((prefix, actionable))\n        return result\n\nrecords = [\n    {\"id\": f\"R-{i}\", \"vendor\": name}\n    for i, name in enumerate([\"Acme Corp\", \"Beta LLC\", \"Gamma Inc\",\n        \"Delta Ltd\", \"Epsilon SA\", \"Zeta GmbH\", \"Eta BV\", \"Theta AG\"])\n]\n\nwindow = SlidingWindow(window_size=4, prefix_ratio=0.5)\nchunks = window.chunks(records)\nprint(f\"Total records: {len(records)}, Chunks: {len(chunks)}, Stride: {window.stride}\")\n\nall_results = []\nfor chunk_idx, (prefix, actionable) in enumerate(chunks):\n    prefix_ids = [r['id'] for r in prefix]\n    action_ids = [r['id'] for r in actionable]\n    print(f\"Chunk {chunk_idx}: prefix={prefix_ids}, actionable={action_ids}\")\n\n    prefix_ctx = \"\"\n    if prefix:\n        prefix_ctx = f\"Previously classified (read-only): {json.dumps(prefix)}\\n\"\n\n    prompts = [\n        f\"{prefix_ctx}Classify this vendor record. Return JSON with fields: id, category, confidence.\\nRecord: {json.dumps(r)}\"\n        for r in actionable\n    ]\n    raw_responses = llm_query_batched(prompts)\n\n    for r, raw in zip(actionable, raw_responses):\n        try:\n            obj = json.loads(raw.strip())\n            all_results.append(obj)\n        except json.JSONDecodeError:\n            all_results.append({\"id\": r[\"id\"], \"error\": \"parse_failed\"})\n\nprint(f\"Total classified: {len(all_results)}\")\nfor res in all_results:\n    print(f\"  {res.get('id', '?')} -> {res.get('category', 'ERROR')}\")"
                    }
                  }
                }
              ]
